// generar_268_enriquecimiento_detalles_y_habitos.js
// CHIQUI Entre Señales — Sub-categorías de enriquecimiento + resumen
// de hábitos en Análisis
//
// NO hay SQL: todo se guarda en la columna detalle de enriquecimientos,
// que ya existe desde el 262.
//
// 1) EL MODAL DE CADA ACTIVIDAD AHORA PREGUNTA QUÉ SE HIZO
//    No son secciones nuevas: son las mismas actividades volviéndose
//    más informativas.
//
//    👃 Juegos de olfato → ¿Qué hicieron? (multi-selección)
//       Buscar premios · Alfombra olfativa · Kong · Caja sorpresa ·
//       Rastro de olores · Otro
//
//    🎾 Juego activo → ¿A qué jugaron? (multi-selección)
//       Pelota · Frisbee · Tira y afloja · Perseguir juguete ·
//       Correr · Otro
//
//    🌳 Lugar nuevo → ¿Dónde? (selección única)
//       Parque · Playa · Cerro o sendero · Ciudad · Casa de otra
//       persona · Veterinario · Otro
//
//    🐶/👨‍👩‍👧‍👦 Socialización → ¿Cómo fue la experiencia? (única, con el
//       semáforo de la app) 🟢 Positiva · 🟡 Neutral · 🔴 Difícil
//
//    🎓 Entrenamiento mantiene sus trucos, ahora dentro del mismo
//       mecanismo genérico (agregar detalle a una actividad futura es
//       sumar una entrada a DETALLE_ENR).
//
// 2) ANÁLISIS MÁS INTELIGENTE — la sección de enriquecimiento pasa de
//    contar a interpretar:
//
//    · Interpretación amable del período, que RECONOCE o SUGIERE pero
//      nunca reprocha:
//        "Excelente variedad de actividades este mes..."
//        "Hace 12 días que no registras actividades de estimulación.
//         Un rato corto de juegos de olfato ya hace diferencia."
//      (El tutor puede estar pasando un mes difícil; la app no está
//      para juzgarlo.)
//    · 🥇 "Lo que más disfruta": el juego más repetido entre olfato y
//      juego activo — ej. "Buscar premios (18 veces)".
//    · 🌳 Lugares nuevos: cuántos tipos distintos y cuáles.
//    · 🐶 Cómo resultaron las socializaciones, con el semáforo. Si hay
//      2 o más experiencias difíciles, una nota suave sugiere
//      conversarlo con el veterinario o un etólogo.
//    · 🎓 Trucos practicados (ya existía).
//
// Uso:
//   node generar_268_enriquecimiento_detalles_y_habitos.js

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/registro-diario/page.tsx",
    base64: ""
  },
  {
    ruta: "app/analisis/page.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 2 archivos escritos. No hay SQL.')
  console.log('git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
